import lighthouse from 'lighthouse';
import * as chromeLauncher from 'chrome-launcher';

describe('Performance Tests', () => {
  let chrome;

  beforeAll(async () => {
    chrome = await chromeLauncher.launch({ chromeFlags: ['--headless'] });
  });

  afterAll(async () => {
    await chrome.kill();
  });

  it('should meet performance benchmarks', async () => {
    const options = {
      logLevel: 'info',
      output: 'json',
      onlyCategories: ['performance'],
      port: chrome.port,
    };

    const runnerResult = await lighthouse('https://trs-web.vercel.app', options);
    const { lhr } = runnerResult;

    expect(lhr.categories.performance.score).toBeGreaterThan(0.9);
    expect(lhr.audits['first-contentful-paint'].numericValue).toBeLessThan(1500);
    expect(lhr.audits['largest-contentful-paint'].numericValue).toBeLessThan(2500);
    expect(lhr.audits['cumulative-layout-shift'].numericValue).toBeLessThan(0.1);
  });

  it('should meet accessibility standards', async () => {
    const options = {
      logLevel: 'info',
      output: 'json',
      onlyCategories: ['accessibility'],
      port: chrome.port,
    };

    const runnerResult = await lighthouse('https://trs-web.vercel.app', options);
    const { lhr } = runnerResult;

    expect(lhr.categories.accessibility.score).toBeGreaterThan(0.9);
  });
});